import { useEffect, useState } from "react";
import { useAuthSession } from "@/hooks/useAuthSession";
import ULThemePageLayout from "@/components/ULThemePageLayout";

/**
 * Store Demo Page
 * Simulates a basic online store with login/logout functionality
 * Used for testing the authentication flow from a client application perspective
 */

interface StoreDemoPageProps {
  onNavigateToLogin?: () => void;
}

export default function StoreDemoPage(props: StoreDemoPageProps) {
  const { user, isAuthenticated, clearAuthUser } = useAuthSession();
  const [displayName, setDisplayName] = useState<string>("");

  useEffect(() => {
    document.title = "Store Demo - Auth0 ACUL Login Example";
    if (user) {
      setDisplayName(user.name || user.username || user.email || "Usuario");
    }
  }, [user]);

  const handleLogout = () => {
    clearAuthUser();
    setDisplayName("");
    // Reload to update UI
    window.location.reload();
  };

  const handleLogin = () => {
    if (props.onNavigateToLogin) {
      props.onNavigateToLogin();
    } else {
      // Fallback: trigger a manual redirect or notification
      alert(
        "Para navegar al login, abre el inspector de contexto y cambia 'screen.name' a 'login'"
      );
    }
  };

  return (
    <ULThemePageLayout className="theme-universal">
      <div className="w-full max-w-4xl mx-auto px-4 py-16">
        {/* Header */}
        <div className="text-center mb-12">
          <h1 className="text-4xl font-bold text-gray-900 mb-2">
            TechStore Online
          </h1>
          <p className="text-gray-600">
            Demo de flujo de autenticación con Auth0 ACUL
          </p>
        </div>

        {/* Auth Status Section */}
        <div className="bg-white rounded-lg shadow-md p-8 mb-12">
          {isAuthenticated && user ? (
            <>
              {/* Authenticated State */}
              <div className="text-center mb-6">
                <div className="inline-block bg-green-100 text-green-800 px-4 py-2 rounded-full mb-4">
                  ✓ Sesión activa
                </div>
              </div>

              <div className="bg-blue-50 rounded-lg p-6 mb-6">
                <h2 className="text-lg font-semibold text-gray-900 mb-4">
                  Información de tu cuenta
                </h2>
                <dl className="space-y-3">
                  {user.name && (
                    <div>
                      <dt className="text-sm font-medium text-gray-500">
                        Nombre
                      </dt>
                      <dd className="text-gray-900">{user.name}</dd>
                    </div>
                  )}
                  {user.username && (
                    <div>
                      <dt className="text-sm font-medium text-gray-500">
                        Usuario
                      </dt>
                      <dd className="text-gray-900">{user.username}</dd>
                    </div>
                  )}
                  <div>
                    <dt className="text-sm font-medium text-gray-500">
                      Email
                    </dt>
                    <dd className="text-gray-900 break-all">{user.email}</dd>
                  </div>
                </dl>
              </div>

              <div className="flex gap-3 justify-center">
                <p className="text-gray-600 text-sm">
                  Bienvenido, {displayName}! 👋
                </p>
              </div>

              <div className="mt-6">
                <button
                  onClick={handleLogout}
                  className="w-full px-6 py-3 bg-red-600 hover:bg-red-700 text-white font-semibold rounded-lg transition-colors"
                >
                  Cerrar sesión
                </button>
              </div>
            </>
          ) : (
            <>
              {/* Unauthenticated State */}
              <div className="text-center mb-6">
                <div className="inline-block bg-gray-100 text-gray-800 px-4 py-2 rounded-full mb-4">
                  No autenticado
                </div>
              </div>

              <p className="text-gray-600 text-center mb-6">
                Inicia sesión para ver tu perfil y acceder a tu cuenta
              </p>

              <button
                onClick={handleLogin}
                className="w-full px-6 py-3 bg-blue-600 hover:bg-blue-700 text-white font-semibold rounded-lg transition-colors"
              >
                Iniciar sesión
              </button>
            </>
          )}
        </div>

        {/* Products Section (Demo) */}
        <div className="mb-12">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">
            Productos destacados
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {[
              {
                name: "Laptop Pro",
                price: "$1,299",
                desc: "Portátil de alta rendimiento",
              },
              {
                name: "Smartphone X",
                price: "$899",
                desc: "Móvil de última generación",
              },
              {
                name: "Tablet Air",
                price: "$649",
                desc: "Tablet versátil y potente",
              },
            ].map((product) => (
              <div
                key={product.name}
                className="bg-gray-50 rounded-lg p-6 border border-gray-200"
              >
                <div className="bg-gray-200 rounded h-40 mb-4 flex items-center justify-center">
                  <span className="text-gray-400 text-sm">Imagen producto</span>
                </div>
                <h3 className="font-semibold text-gray-900 mb-2">
                  {product.name}
                </h3>
                <p className="text-sm text-gray-600 mb-3">{product.desc}</p>
                <div className="flex justify-between items-center">
                  <span className="text-lg font-bold text-blue-600">
                    {product.price}
                  </span>
                  <button
                    disabled={!isAuthenticated}
                    className="px-3 py-2 text-sm font-medium bg-blue-600 hover:bg-blue-700 disabled:bg-gray-400 text-white rounded transition-colors"
                  >
                    Comprar
                  </button>
                </div>
              </div>
            ))}
          </div>
          {!isAuthenticated && (
            <p className="text-sm text-gray-500 text-center mt-4">
              💡 Inicia sesión para comprar productos
            </p>
          )}
        </div>

        {/* Footer Info */}
        <div className="bg-gray-50 rounded-lg p-6 border border-gray-200">
          <h3 className="font-semibold text-gray-900 mb-2">
            ℹ️ Cómo funciona esta demo
          </h3>
          <ul className="text-sm text-gray-600 space-y-2">
            <li>
              ✓ Esta es una página simulada de una tienda en línea (Store Demo)
            </li>
            <li>
              ✓ Haz clic en "Iniciar sesión" para ir a la pantalla de login de
              Auth0
            </li>
            <li>
              ✓ Completa el login y la información se guardará en tu navegador
            </li>
            <li>
              ✓ Después de autenticarte, volverás a ver esta página con tu
              información
            </li>
            <li>✓ Haz clic en "Cerrar sesión" para limpiar tu sesión</li>
          </ul>
        </div>
      </div>
    </ULThemePageLayout>
  );
}
